// resourceIDFieldOverrides projects per-resource IDField (set by the profiler
// from x-resource-id or response-schema fallback) into a runtime lookup map.
// UpsertBatch consults this first so the templated path wins over the
// generic fallback list. Empty when no resource declared an override; the
// runtime fallback list still applies.
//
// Includes both flat resources and dependent (parent-child) resources so a
// child path-item annotated with x-resource-id resolves the same as a flat
// path-item.
var resourceIDFieldOverrides = map[string]string{
	"audiences": "id",
}

// genericIDFieldFallbacks is the runtime safety net for resources that did
// NOT receive a templated IDField. API-specific names belong in spec
// annotations (x-resource-id), not this list. Order matters: vendor
// identifier names (gid, sid, uid, uuid, guid) take precedence over `name`
// so APIs like Asana (gid) and Twilio (sid) don't fall through to a display
// field and upsert on names — see #1394.
var genericIDFieldFallbacks = []string{"id", "ID", "gid", "sid", "uid", "uuid", "guid", "name", "slug", "key", "code"}

// UpsertBatch inserts or replaces multiple records in a single transaction
// and returns (stored, extractFailures, err). stored counts rows landed in
// the generic resources table; extractFailures counts items that survived
// JSON unmarshal but had no extractable primary key (templated IDField AND
// generic fallback both missed). callers (sync.go.tmpl) compare these
// against len(items) to emit the per-item primary_key_unresolved warning
// and the F4b stored_count_zero_after_extraction probe.
//
// For resource types that have a domain-specific typed table, the per-item
// generic insert is followed by a dispatch to the matching upsert<Pascal>Tx
// inside the same transaction. Without that dispatch, paginated syncs would
// only populate the generic resources table — typed tables (and indexed
// columns like parent_id added by dependent-resource sync) would stay empty.
//
// Each typed-table dispatch runs inside a per-item SAVEPOINT so a constraint
// failure in the typed insert (e.g. NOT NULL parent FK when the generator
// didn't populate the parent path placeholder) rolls back only that typed
// upsert. The generic resources row inserted just above it survives the
// rollback, so successful API fetches never strand in memory because one
// downstream typed table is misconfigured. Failures are surfaced via a
// trailing stderr warning rather than aborting the batch.
func (s *Store) UpsertBatch(resourceType string, items []json.RawMessage) (int, int, error) {
	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return 0, 0, fmt.Errorf("starting batch transaction: %w", err)
	}
	defer tx.Rollback()

	var stored, skippedCount, extractFailures, typedFailures int
	for i, item := range items {
		var obj map[string]any
		if err := json.Unmarshal(item, &obj); err != nil {
			skippedCount++
			continue
		}
		// Templated IDField wins; generic fallback list runs second when
		// the override is empty OR the override field is absent on this
		// particular item (response shape mismatches happen even when the
		// spec declares x-resource-id).
		var id string
		if override, ok := resourceIDFieldOverrides[resourceType]; ok && override != "" {
			if v := lookupFieldValue(obj, override); v != nil {
				s := fmt.Sprintf("%v", v)
				if s != "" && s != "<nil>" {
					id = s
				}
			}
		}
		if id == "" {
			for _, key := range genericIDFieldFallbacks {
				if v := lookupFieldValue(obj, key); v != nil {
					s := fmt.Sprintf("%v", v)
					if s != "" && s != "<nil>" {
						id = s
						break
					}
				}
			}
		}
		if id == "" {
			skippedCount++
			extractFailures++
			continue
		}

		if err := s.upsertGenericResourceTx(tx, resourceType, id, item); err != nil {
			// Return the running stored count rather than zero so callers
			// inspecting partial progress on failure see what already
			// landed in earlier loop iterations.
			return stored, extractFailures, fmt.Errorf("upserting %s/%s: %w", resourceType, id, err)
		}
		stored++

		savepoint := fmt.Sprintf("pp_typed_%d", i)
		if _, err := tx.Exec("SAVEPOINT " + savepoint); err != nil {
			return stored, extractFailures, fmt.Errorf("savepoint begin for %s/%s: %w", resourceType, id, err)
		}

		var typedErr error
		switch resourceType {
		case "account-exports":
			typedErr = s.upsertAccountExportsTx(tx, id, obj, item)
		case "audiences":
			typedErr = s.upsertAudiencesTx(tx, id, obj, item)
		case "contacts":
			typedErr = s.upsertContactsTx(tx, id, obj, item)
		case "authorized-apps":
			typedErr = s.upsertAuthorizedAppsTx(tx, id, obj, item)
		case "automations":
			typedErr = s.upsertAutomationsTx(tx, id, obj, item)
		case "automations_actions":
			typedErr = s.upsertAutomationsActionsTx(tx, id, obj, item)
		case "emails":
			typedErr = s.upsertEmailsTx(tx, id, obj, item)
		case "removed_subscribers":
			typedErr = s.upsertRemovedSubscribersTx(tx, id, obj, item)
		case "batch-webhooks":
			typedErr = s.upsertBatchWebhooksTx(tx, id, obj, item)
		case "batches":
			typedErr = s.upsertBatchesTx(tx, id, obj, item)
		case "campaign-folders":
			typedErr = s.upsertCampaignFoldersTx(tx, id, obj, item)
		case "campaigns":
			typedErr = s.upsertCampaignsTx(tx, id, obj, item)
		case "campaigns_actions":
			typedErr = s.upsertCampaignsActionsTx(tx, id, obj, item)
		case "campaigns_content":
			typedErr = s.upsertCampaignsContentTx(tx, id, obj, item)
		case "feedback":
			typedErr = s.upsertFeedbackTx(tx, id, obj, item)
		case "send_checklist":
			typedErr = s.upsertSendChecklistTx(tx, id, obj, item)
		case "connected-sites":
			typedErr = s.upsertConnectedSitesTx(tx, id, obj, item)
		case "connected_sites_actions":
			typedErr = s.upsertConnectedSitesActionsTx(tx, id, obj, item)
		case "conversations":
			typedErr = s.upsertConversationsTx(tx, id, obj, item)
		case "messages":
			typedErr = s.upsertMessagesTx(tx, id, obj, item)
		case "ecommerce":
			typedErr = s.upsertEcommerceTx(tx, id, obj, item)
		case "facebook-ads":
			typedErr = s.upsertFacebookAdsTx(tx, id, obj, item)
		case "file-manager":
			typedErr = s.upsertFileManagerTx(tx, id, obj, item)
		case "landing-pages":
			typedErr = s.upsertLandingPagesTx(tx, id, obj, item)
		case "landing_pages_actions":
			typedErr = s.upsertLandingPagesActionsTx(tx, id, obj, item)
		case "landing_pages_content":
			typedErr = s.upsertLandingPagesContentTx(tx, id, obj, item)
		case "lists":
			typedErr = s.upsertListsTx(tx, id, obj, item)
		case "lists_abuse_reports":
			typedErr = s.upsertListsAbuseReportsTx(tx, id, obj, item)
		case "activity":
			typedErr = s.upsertActivityTx(tx, id, obj, item)
		case "clients":
			typedErr = s.upsertClientsTx(tx, id, obj, item)
		case "growth_history":
			typedErr = s.upsertGrowthHistoryTx(tx, id, obj, item)
		case "interest_categories":
			typedErr = s.upsertInterestCategoriesTx(tx, id, obj, item)
		case "lists_locations":
			typedErr = s.upsertListsLocationsTx(tx, id, obj, item)
		case "members":
			typedErr = s.upsertMembersTx(tx, id, obj, item)
		case "merge_fields":
			typedErr = s.upsertMergeFieldsTx(tx, id, obj, item)
		case "segments":
			typedErr = s.upsertSegmentsTx(tx, id, obj, item)
		case "signup_forms":
			typedErr = s.upsertSignupFormsTx(tx, id, obj, item)
		case "surveys":
			typedErr = s.upsertSurveysTx(tx, id, obj, item)
		case "tag_search":
			typedErr = s.upsertTagSearchTx(tx, id, obj, item)
		case "webhooks":
			typedErr = s.upsertWebhooksTx(tx, id, obj, item)
		case "reporting":
			typedErr = s.upsertReportingTx(tx, id, obj, item)
		case "reports":
			typedErr = s.upsertReportsTx(tx, id, obj, item)
		case "reports_abuse_reports":
			typedErr = s.upsertReportsAbuseReportsTx(tx, id, obj, item)
		case "advice":
			typedErr = s.upsertAdviceTx(tx, id, obj, item)
		case "click_details":
			typedErr = s.upsertClickDetailsTx(tx, id, obj, item)
		case "domain_performance":
			typedErr = s.upsertDomainPerformanceTx(tx, id, obj, item)
		case "ecommerce_product_activity":
			typedErr = s.upsertEcommerceProductActivityTx(tx, id, obj, item)
		case "eepurl":
			typedErr = s.upsertEepurlTx(tx, id, obj, item)
		case "email_activity":
			typedErr = s.upsertEmailActivityTx(tx, id, obj, item)
		case "reports_locations":
			typedErr = s.upsertReportsLocationsTx(tx, id, obj, item)
		case "open_details":
			typedErr = s.upsertOpenDetailsTx(tx, id, obj, item)
		case "sent_to":
			typedErr = s.upsertSentToTx(tx, id, obj, item)
		case "sub_reports":
			typedErr = s.upsertSubReportsTx(tx, id, obj, item)
		case "unsubscribed":
			typedErr = s.upsertUnsubscribedTx(tx, id, obj, item)
		case "sms-campaigns":
			typedErr = s.upsertSmsCampaignsTx(tx, id, obj, item)
		case "sms_campaigns_actions":
			typedErr = s.upsertSmsCampaignsActionsTx(tx, id, obj, item)
		case "sms_campaigns_content":
			typedErr = s.upsertSmsCampaignsContentTx(tx, id, obj, item)
		case "template-folders":
			typedErr = s.upsertTemplateFoldersTx(tx, id, obj, item)
		case "templates":
			typedErr = s.upsertTemplatesTx(tx, id, obj, item)
		case "default_content":
			typedErr = s.upsertDefaultContentTx(tx, id, obj, item)
		case "verified-domains":
			typedErr = s.upsertVerifiedDomainsTx(tx, id, obj, item)
		case "verified_domains_actions":
			typedErr = s.upsertVerifiedDomainsActionsTx(tx, id, obj, item)
		}

		if typedErr != nil {
			if _, rbErr := tx.Exec("ROLLBACK TO SAVEPOINT " + savepoint); rbErr != nil {
				return stored, extractFailures, fmt.Errorf("rollback to savepoint for %s/%s (typed err: %v): %w", resourceType, id, typedErr, rbErr)
			}
			if _, relErr := tx.Exec("RELEASE SAVEPOINT " + savepoint); relErr != nil {
				return stored, extractFailures, fmt.Errorf("release savepoint after rollback for %s/%s: %w", resourceType, id, relErr)
			}
			typedFailures++
			continue
		}
		if _, err := tx.Exec("RELEASE SAVEPOINT " + savepoint); err != nil {
			return stored, extractFailures, fmt.Errorf("release savepoint for %s/%s: %w", resourceType, id, err)
		}
	}

	// Warn when most items in a batch lack an extractable ID — this likely
	// means the API uses a primary key field we don't recognize yet.
	if skippedCount > 0 && len(items) > 0 && skippedCount*2 > len(items) {
		fmt.Fprintf(os.Stderr, "warning: %d/%d %s items skipped (no extractable ID field found)\n", skippedCount, len(items), resourceType)
	}
	// Surface typed-table failures without aborting the batch. Generic rows
	// already committed; only the typed projection failed.
	if typedFailures > 0 {
		fmt.Fprintf(os.Stderr, "warning: %d/%d %s items: typed-table upsert failed; generic resources rows preserved\n", typedFailures, len(items), resourceType)
	}

	if err := tx.Commit(); err != nil {
		return 0, extractFailures, err
	}
	return stored, extractFailures, nil
}

// SearchAuthorizedApps searches the authorized_apps_fts index with optional filters.
func (s *Store) SearchAuthorizedApps(query string, limit int) ([]json.RawMessage, error) {
	if limit <= 0 {
		limit = 50
	}
	rows, err := s.db.Query(
		`SELECT t.data FROM "authorized_apps" t
		 JOIN "authorized_apps_fts" ON "authorized_apps_fts".rowid = t.rowid
		 WHERE "authorized_apps_fts" MATCH ?
		 ORDER BY rank LIMIT ?`,
		query, limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var results []json.RawMessage
	for rows.Next() {
		var data string
		if err := rows.Scan(&data); err != nil {
			return nil, err
		}
		results = append(results, json.RawMessage(data))
	}
	return results, rows.Err()
}

// SearchEcommerce searches the ecommerce_fts index with optional filters.
func (s *Store) SearchEcommerce(query string, limit int) ([]json.RawMessage, error) {
	if limit <= 0 {
		limit = 50
	}
	rows, err := s.db.Query(
		`SELECT t.data FROM "ecommerce" t
		 JOIN "ecommerce_fts" ON "ecommerce_fts".rowid = t.rowid
		 WHERE "ecommerce_fts" MATCH ?
		 ORDER BY rank LIMIT ?`,
		query, limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var results []json.RawMessage
	for rows.Next() {
		var data string
		if err := rows.Scan(&data); err != nil {
			return nil, err
		}
		results = append(results, json.RawMessage(data))
	}
	return results, rows.Err()
}

